import { createSlice } from "@reduxjs/toolkit";

const initialState = {
  autoDrivingCars: {},
  fasAebSwitch: true,
}

const sendPointSlice = createSlice({
  name: "sendPoint",
  initialState,
  reducers: {
    setAutoDrivingCars: (state, action) => {
      state.autoDrivingCars = action.payload;
    },

    setFasAebSwitch: (state, action) => {
      state.fasAebSwitch = action.payload;
    }
  },
});

export const {
  setAutoDrivingCars,
  setFasAebSwitch,
} = sendPointSlice.actions;

export default sendPointSlice.reducer;
