import { createSlice } from "@reduxjs/toolkit";

const initialState = {
  blockObsId: null,
  showBypass: false,
  vehicleStatus: {},
  adVersion: '',
  currentMap: '',
}

const realtimeSlice = createSlice({
  name: "realtime",
  initialState,
  reducers: {
    setBlockObsId: (state, action) => {
      state.blockObsId = action.payload;
    },

    toggleBypass: (state) => {
      state.showBypass = !state.showBypass;
    },

    setVehicleStatus: (state, action) => {
      state.vehicleStatus = action.payload;
    },

    setAdVersion: (state, action) => {
      state.adVersion = action.payload;
    },

    setCurrentMap: (state, action) => {
      state.currentMap = action.payload;
    }
  },
});

export const {
  toggleBypass,
  setBlockObsId,
  setVehicleStatus,
  setAdVersion,
  setCurrentMap
} = realtimeSlice.actions;

export default realtimeSlice.reducer;
