import { createSlice } from "@reduxjs/toolkit";

const initialState = {
  vehicleConfig: {},
};

const SettingSlice = createSlice({
  name: "setting",
  initialState,
  reducers: {
    setVehicleConfig: (state, action) => {
      state.vehicleConfig = action.payload;
    }
  },
});

export const { setVehicleConfig } = SettingSlice.actions;

export default SettingSlice.reducer;
