import React, { Suspense, useEffect } from "react";
import { App as AntdApp, message, Modal } from "antd";
import { RouterProvider } from "react-router-dom";
import route from "./route";
import { useDispatch, useSelector } from "react-redux";
import {WS} from "./utils/websocket";
import {
  toggleBypass,
  setBlockObsId,
  setVehicleStatus,
  setAdVersion,
  setCurrentMap,
} from "./store/realtimeSlice.js";
import { setAutoDrivingCars, setFasAebSwitch } from "./store/sendPointSlice.js";
import { setVehicleConfig } from "./store/settingSlice.js";

const worker = new Worker(new URL("./utils/webworker.js", import.meta.url));

WS.connect((data) => {
  worker.postMessage({
    source: "realtime",
    data: data,
  });
})

const App = () => {
  const dispatch = useDispatch();
  const showBypass = useSelector((state) => state.realtime.showBypass);
  const fasAebSwitch = useSelector((state) => state.realtime.fasAebSwitch);
  const blockObsId = useSelector((state) => state.realtime.blockObsId);

  useEffect(() => {
    worker.onmessage = (event) => {
      const data = event.data;
      switch (data.type) {
        case "SimWorldUpdate":
          if (data.blockObsId) {
            dispatch(setBlockObsId(data.blockObsId));
          }
          if (!!data.borrowRequest !== showBypass) {
            dispatch(toggleBypass(data.borrowRequest));
          }
          if (data.autoDrivingCar) {
            dispatch(setAutoDrivingCars(data.autoDrivingCar));
          }
          if (
            data.fasAebSwitch !== "undefined" &&
            data.fasAebSwitch !== fasAebSwitch
          ) {
            dispatch(setFasAebSwitch(data.fasAebSwitch));
          }
          break;
        case "SystemInfo":
          dispatch(setVehicleStatus(data.data));
          break;
        case "ProjectVersionCheckResult":
          dispatch(setAdVersion(data.version));
          break;
        case "HMIStatus":
          dispatch(setCurrentMap(data.data.currentMap));
          break;
        case "VehicleConfigInfo":
          dispatch(setVehicleConfig(data.config));
          break;
        case "ModifyVehicleConfigResult":
          if (data) {
            data.status === true
              ? message.success("Vehicle config updated successfully.")
              : message.error("Vehicle config update failed.");
            WS.getVehicleConfig();
          }
          break;
        case "ModifyFasAebInfoResult":
          if (data) {
            data.data.result
              ? message.success("FAS/AEB updated successfully.")
              : message.error("FAS/AEB update failed.");
          }
          break;
        default:
          break;
      }
    };
  }, [dispatch, showBypass, fasAebSwitch]);

  const handleBypassOk = () => {
    WS.requestBypassObstacle(blockObsId, true);
  };

  const handleBypassCancel = () => {
    WS.requestBypassObstacle(blockObsId, false);
  };

  return (
    <AntdApp>
      <Modal
        title="ByPass"
        closable={{ "aria-label": "Custom Close Button" }}
        open={showBypass}
        onOk={handleBypassOk}
        onCancel={handleBypassCancel}
      >
        <p>Do you agree to bypass the obstacle?</p>
      </Modal>
      <Suspense fallback={<div>Loading...</div>}>
        <RouterProvider router={route} />
      </Suspense>
    </AntdApp>
  );
};

export default App;
