const server = window.location.origin;
const link = document.createElement("a");
link.href = server;
const protocol = "ws";
const port =
  process.env.NODE_ENV === "production" ? window.location.port : 8888;

const url = `${protocol}://${link.hostname}:${port}/websocket`;
class WebSocketClient {
  constructor() {
    this.url = url;

    this.ws = null;
    this.reconnectInterval = 1000;
    this.isManuallyClosed = false;
    this.updateProjectVersion = true;
    this.updateVehicleConfig = true;
    this.simWorldLastUpdateTimestamp = 0;
    this.worker = new Worker(new URL("./webworker.js", import.meta.url));
  }

  connect(onMessage) {
    this.ws = new WebSocket(this.url);
    this.ws.binaryType = "arraybuffer";

    this.ws.onopen = () => {
      console.log("WebSocket connected");
    };

    this.ws.onmessage = (event) => {
      onMessage && onMessage(event.data);
    };

    this.ws.onerror = (error) => {
      console.error("WebSocket Error:", error);
    };

    this.ws.onclose = () => {
      if (!this.isManuallyClosed) {
        setTimeout(() => this.connect(onMessage), this.reconnectInterval);
      }
    };

    clearInterval(this.timer);
    this.timer = setInterval(() => {
      if (this.ws.readyState === WebSocket.OPEN) {
        this.requestSimulationWorld();
        this.RequestSystemInfo();
        if (this.updateProjectVersion) {
          this.getProjectVersion();
          this.updateProjectVersion = false;
        }
        if (this.updateVehicleConfig) {
          this.getVehicleConfig();
          this.updateVehicleConfig = false;
        }
      }
    }, 100);
  }

  send(data) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify(data));
    } else {
      console.warn("WebSocket not connected");
    }
  }

  close() {
    this.isManuallyClosed = true;
    this.ws && this.ws.close();
  }

  requestSimulationWorld() {
    this.ws.send(
      JSON.stringify({
        type: "RequestSimulationWorld",
      })
    );
  }

  RequestSystemInfo() {
    this.ws.send(
      JSON.stringify({
        type: "RequestSystemInfo",
      })
    );
  }

  getProjectVersion() {
    this.ws.send(
      JSON.stringify({
        type: "ProjectVersion",
      })
    );
  }

  requestBypassObstacle(id, agree) {
    this.ws.send(
      JSON.stringify({
        type: "RequestBypassObstacle",
        data: {
          id,
          agree,
        },
      })
    );
  }

  sendDemonstrateRequest(start, start_heading, end, endType, blacklistedLane) {
    const request = {
      type: "SendRoutingRequest",
      start,
      end,
      waypoint: [],
    };

    if (endType) {
      request.end.type = endType;
    }

    if (start_heading) {
      request.start.heading = start_heading;
    }

    if (blacklistedLane) {
      request.blacklistedLane = blacklistedLane.split(",");
    }

    this.ws.send(JSON.stringify(request));
  }

  requestRoute(
    start,
    start_heading,
    waypoint,
    end,
    parkingInfo,
    isLoopRunning
  ) {
    const request = {
      type: "SendRoutingRequest",
      start,
      end,
      waypoint,
      isLoopRunning,
    };

    if (parkingInfo) {
      request.parkingInfo = parkingInfo;
    }

    if (start_heading) {
      request.start.heading = start_heading;
    }
    this.ws.send(JSON.stringify(request));
  }

  requestImmediatelyArrived() {
    this.ws.send(
      JSON.stringify({
        type: "RequestImmediatelyArrived",
      })
    );
  }

  changeFASAEBStatus(status, password) {
    this.ws.send(
      JSON.stringify({
        type: "ModifyFasAebInfo",
        status,
        password,
      })
    );
  }

  getVehicleConfig() {
    this.ws.send(
      JSON.stringify({
        type: "GetVehicleConfig",
      })
    );
  }

  modifyVehicleConfig(config) {
    this.ws.send(
      JSON.stringify({
        type: "ModifyVehicleConfig",
        config,
      })
    );
  }
}

export default WebSocketClient;

export const WS = new WebSocketClient();
