import { createBrowserRouter, Navigate } from 'react-router-dom'
import { lazy } from 'react';
import AppLayout from './../views/AppLayout';

const RealtimeApp = lazy(() => import('./../views/RealtimeInfo'));
const SendPoints = lazy(() => import('./../views/SendPoints'));
const EditSetting = lazy(() => import('./../views/EditSetting'));
const NotFound = lazy(() => import('./../views/NotFound'));

const router = createBrowserRouter([
  {
    path: '/',
    element: <AppLayout />,
    children: [
      {
        index: true,
        element: <Navigate to="/realtime" replace />
      },
      {
        path: 'realtime',
        element: <RealtimeApp />,
      },
      {
        path: 'station',
        element: <SendPoints />,
      },
      {
        path: 'setting',
        element: <EditSetting />,
      }
    ]
  },
  {
    path: '*',
    element: <NotFound />
  }
])

export default router